const items = $input.all();
const valid = [];
const invalid = [];

for (const item of items) {
  const d = item.json;

  // Validate mandatory fields
  const missing = [];
  if (!d.full_name) missing.push('full_name');
  if (!d.email) missing.push('email');
  if (!d.normalized_url) 
    missing.push('normalized_url');

  if (missing.length > 0) {
    invalid.push({
      record_id: d.record_id,
      reason: 'Missing: ' + missing.join(', ')
    });
    continue;
  }

  // Transform snake_case → CRM request shape
  const nameParts = (d.full_name || '').split(' ');
  const firstName = nameParts[0] || '';
  const lastName = nameParts.slice(1).join(' ') || '';

  // Normalize phone
  let phone = (d.phone || '').replace(/\s+/g, '');
  if (phone && !phone.startsWith('+')) {
    phone = '+' + phone;
  }

  valid.push({
    json: {
      // Original DB fields
      record_id: d.record_id,
      normalized_url: d.normalized_url,

      // CRM shaped payload
      crm_payload: {
        firstName: firstName,
        lastName: lastName,
        fullName: d.full_name,
        emailAddress: d.email,
        phoneNumber: phone,
        organization: d.company || '',
        jobTitle: d.job_title || '',
        linkedInUrl: d.normalized_url,
        source: 'n8n_pipeline',
        stage: 'CRM_PENDING'
      },

      // Keep for logging
      full_name: d.full_name,
      email: d.email,
      phone: phone,
      company: d.company,
      job_title: d.job_title,
      validation: 'passed'
    }
  });
}

// Log invalid records
if (invalid.length > 0) {
  console.log('Invalid records skipped:',
    JSON.stringify(invalid));
}

if (valid.length === 0) {
  throw new Error(
    'No valid S6 records to process. ' +
    'Invalid: ' + JSON.stringify(invalid)
  );
}

return valid;
